@use '../../styles/tokens' as *;

.action-panel {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 36px;
  padding: 0 $space-3;
  border-top: 1px solid $color-border;
  background-color: $color-surface-footer;
  flex-shrink: 0;

  &__primary,
  &__secondary {
    display: flex;
    align-items: center;
    gap: $space-3;
  }

  &__action {
    display: flex;
    align-items: center;
    gap: $space-2;
    background: none;
    border: none;
    padding: 0;
    cursor: pointer;
    color: $color-text-secondary;
    font-family: $font-family;
    font-size: $font-xs;
    line-height: 1;
    transition: color $transition-fast ease;

    &:hover {
      color: $color-text-primary;
    }

    &:focus-visible {
      outline: 2px solid $color-accent;
      outline-offset: 2px;
      border-radius: $radius-sm;
    }
  }

  &__label {
    white-space: nowrap;
  }

  &__shortcut {
    display: inline-flex;
    align-items: center;
    gap: $space-half;
  }
}

